# frozen_string_literal: true

module Agentkit
  # Code generated by CodificadorAgent for an accepted EvolutionItem.
  # Reviewed, applied (or rejected) by a developer via the Fábrica UI.
  #
  # status: draft | reviewed | applied | failed
  class CodeGeneration < ApplicationRecord
    self.table_name = "agentkit_code_generations"

    # ─── Associations ─────────────────────────────────────────────────────────
    belongs_to :evolution_item,
               class_name:  "Agentkit::EvolutionItem",
               foreign_key: :evolution_item_id
    belongs_to :user

    # ─── Validations ──────────────────────────────────────────────────────────
    validates :target_file, presence: true
    validates :status, inclusion: { in: %w[draft reviewed applied failed] }

    # ─── Scopes ───────────────────────────────────────────────────────────────
    scope :draft,    -> { where(status: "draft") }
    scope :applied,  -> { where(status: "applied") }
    scope :failed,   -> { where(status: "failed") }
    scope :recent,   -> { order(created_at: :desc) }

    # ─── Helpers ──────────────────────────────────────────────────────────────
    def applied?
      status == "applied"
    end

    def apply!(applier_user)
      # Write generated_code to target_file on disk (sandboxed to app root).
      app_root = Rails.root
      target   = app_root.join(target_file).cleanpath

      # Safety: only write within the Rails root
      unless target.to_s.start_with?(app_root.to_s)
        update!(status: "failed")
        raise SecurityError, "Target file outside Rails root: #{target_file}"
      end

      FileUtils.mkdir_p(target.dirname)
      target.write(generated_code)
      update!(status: "applied", applied_at: Time.current)
    rescue StandardError => e
      update!(status: "failed")
      raise e
    end
  end
end
